const output = $input.item.json.output;

const escMatch  = output.match(/##ESCALATE:([^#]+)##/);
const ceoMatch  = output.match(/##CEO_NOTIFY:([^#]+)##/);

const cleanReply = output
  .replace(/##ESCALATE:[^#]+##/g, '')
  .replace(/##CEO_NOTIFY:[^#]+##/g, '')
  .trim();

let tagType = 'none';
let tagReason = '';
let productNeeded = '';

if (ceoMatch) {
  const parts = ceoMatch[1].split(':');
  tagType       = 'ceo_notify';
  tagReason     = parts[0].trim();
  productNeeded = parts[1] ? parts[1].trim() : '';
} else if (escMatch) {
  tagType   = 'escalate';
  tagReason = escMatch[1].trim();
}

return {
  json: {
    ...$input.item.json,
    tagType,
    tagReason,
    productNeeded,
    cleanReply
  }
};

// Collect ALL product rows into one grouped string
const products = $input.all();

// Build structured JSON array
const productJson = products.map(item => {
  const p = item.json;
  return {
    id:          p.id          || null,
    name:        p.name        || 'Unknown',
    brand:       p.brand       || 'N/A',
    price:       p.price       ? Number(p.price) : 0,
    priceFormatted: p.price    ? '₦' + Number(p.price).toLocaleString() : 'N/A',
    features:    p.features    || 'N/A',
    specs:       p.specs       || 'N/A',
    description: p.description || '',
    inStock:     p.stock       ? true : false,
    stockLabel:  p.stock       ? 'IN STOCK' : 'OUT OF STOCK'
  };
});

// Build readable string for AI prompt
const productContext = productJson.map(p => {
  return `[${p.id}] ${p.name} | Brand: ${p.brand} | Price: ${p.priceFormatted} | Features: ${p.features} | Specs: ${p.specs} | ${p.description} | Stock: ${p.stockLabel}`;
}).join('\n');

return [{
  json: {
    productContext:     productContext,
    productContextJson: productJson,
    totalProducts:      productJson.length,
    inStockCount:       productJson.filter(p => p.inStock).length,
    outOfStockCount:    productJson.filter(p => !p.inStock).length
  }
}];

const rows = $input.all();

if (rows.length === 0) {
  return [{ json: { history: '' } }];
}

const history = rows
  .filter(item => item.json && item.json.role && item.json.message)
  .map(item => item.json.role.toUpperCase() + ': ' + item.json.message)
  .join('\n');

return [{ json: { history: history } }];

let reply = '';

try {
  reply = $input.first().json.finalReply || '';
} catch(e) {
  reply = '';
}

// Remove bad control characters
reply = reply
  .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, '')
  .replace(/\r\n/g, ' ')   // replace newlines with space
  .replace(/\r/g,   ' ')   // replace carriage return with space
  .replace(/\n/g,   ' ')   // replace all newlines with space
  .replace(/\t/g,   ' ')   // replace tabs with space
  .replace(/\s+/g,  ' ')   // collapse multiple spaces into one
  .replace(/"/g,    "'")   // replace double quotes with single quotes
  .replace(/\\/g,   '')    // remove backslashes
  .trim();

// Fallback if empty
if (!reply || reply.length === 0) {
  reply = 'Thank you for your message! How can I help you today?';
}

// Clean phone number
let phone = '';
try {
  phone = ($('Build AI Context').first().json.phone || '')
    .toString()
    .replace(/\+/g, '')
    .replace(/\s/g, '')
    .replace(/-/g,  '')
    .trim();
} catch(e) {
  phone = '';
}

// Verify it is truly single line
const isSingleLine = !reply.includes('\n') && !reply.includes('\r');

return [{
  json: {
    phone:          phone,
    name:           $('Build AI Context').first().json.name           || '',
    message:        $('Build AI Context').first().json.message       || '',
    history:        $('Build AI Context').first().json.history        || '',
    productContext: $('Build AI Context').first().json.productContext || '',
    finalReply:     reply,
    isSingleLine:   isSingleLine
  }
}];

const items = $input.all();

// Separate customers from product
const customers = items.filter(i => i.json.phone && !i.json.price);
const products  = items.filter(i => i.json.price);
const product   = products[0] ? products[0].json : null;

if (!product) {
  return [{ json: { error: 'No product found', customers: [], product: null } }];
}

return customers.map(c => ({
  json: {
    customerPhone: c.json.phone,
    customerName:  c.json.name || 'Customer',
    productName:   product.name,
    productBrand:  product.brand,
    productPrice:  Number(product.price).toLocaleString(),
    blastMessage:  'Sannu ' + (c.json.name || 'Customer') + '! Dr. Apple Phone Store has a new arrival: ' + product.name + ' by ' + product.brand + ' for only N' + Number(product.price).toLocaleString() + '. Available now at Farm Centre Market Kano! Reply to order. 🍎'
  }
}));

const response = $input.item.json;
const text = response.content[0].text;
const clean = text.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { customer_name: 'Unknown', items: [], total: 0 };
}

return {
  json: {
    ceoPhone:     $('Normalize Message').item.json.phone,
    customerName: parsed.customer_name || 'Unknown',
    items:        parsed.items         || [],
    total:        parsed.total         || 0,
    parsedInvoice: parsed
  }
};

const inv    = $('Extract Invoice Data').item.json;
const cust   = $('Lookup Customer').item.json;
const stored = $('Insert Invoice').item.json;

const items  = inv.items || [];
const lines  = items.map(i =>
  i.product + ' x' + i.qty + ' - N' + Number(i.unit_price).toLocaleString() + ' = N' + Number(i.subtotal).toLocaleString()
).join(' | ');

const today  = new Date().toLocaleDateString('en-NG');
const invoiceMsg = 'INVOICE - Dr. Apple Phone Store Farm Centre Market Kano | Customer: ' + (cust.name || inv.customerName) + ' | Date: ' + today + ' | Items: ' + lines + ' | TOTAL: N' + Number(inv.total).toLocaleString() + ' | Status: Unpaid | Thank you for choosing Dr. Apple! 🍎';
