// CEO types:
// /invoice_gen Aminu Musa | iPhone 15 256GB | 1 | 750000
// /invoice_gen Fatima | MacBook Air M3 | 1 | 1200000 | Case | 1 | 5000

const raw = $('Is Blast?').first().json.message || '';
const ceoPhone = $('Is Blast?').first().json.phone;

// Remove the command prefix
const body = raw.replace(/\/invoice_gen/i, '').trim();

// Split by pipe
const parts = body.split('|').map(p => p.trim());

if (parts.length < 4) {
  return [{
    json: {
      parseError: true,
      errorMsg: 'Wrong format. Use: /invoice_gen Customer Name | Product | Qty | Price',
      ceoPhone: ceoPhone,
      customerName: '',
      items: [],
      total: 0
    }
  }];
}

// First part is always customer name
const customerName = parts[0];

// Remaining parts are groups of: product | qty | price
const items = [];
let total = 0;

// Parse items in groups of 3
for (let i = 1; i < parts.length; i += 3) {
  const product   = parts[i]   || 'Unknown';
  const qty       = parseInt(parts[i+1]) || 1;
  const unitPrice = parseFloat((parts[i+2] || '0').replace(/,/g, '')) || 0;
  const subtotal  = qty * unitPrice;
  total += subtotal;

  items.push({
    product:    product,
    qty:        qty,
    unit_price: unitPrice,
    subtotal:   subtotal
  });
}

return [{
  json: {
    parseError:   false,
    ceoPhone:     ceoPhone,
    customerName: customerName,
    items:        items,
    total:        total
  }
}];

